// @n8n-harness:primitive — exempt from pure-function discipline
const lockValue = $json.LOCK_VALUE;
const providedLockId = $('Execute Workflow Trigger').item.json.lock_id;

// Absent key (Redis GET miss) => lock already released. Treat as idempotent success.
if (lockValue === null || lockValue === undefined || lockValue === '') {
  return {
    json: {
      is_match: true,
      already_released: true,
      provided_lock_id: providedLockId,
      stored_lock_id: null,
      workflow_id: 'none',
      workflow_name: 'none (key absent)',
      execution_id: 'none',
      locked_at: 'none'
    }
  };
}

// Try to parse as JSON (new format), fall back to string (old format)
let parsedLock;
try {
  parsedLock = JSON.parse(lockValue);
} catch (e) {
  // Old format: lock value is just the UUID string
  parsedLock = { lock_id: lockValue, workflow_id: 'unknown', workflow_name: 'unknown (legacy lock)', execution_id: 'unknown', locked_at: 'unknown' };
}

// Defensive: JSON.parse('null') or JSON.parse of a non-object returns a non-object value.
if (parsedLock === null || typeof parsedLock !== 'object') {
  parsedLock = { lock_id: String(lockValue), workflow_id: 'unknown', workflow_name: 'unknown (legacy lock)', execution_id: 'unknown', locked_at: 'unknown' };
}

const isMatch = parsedLock.lock_id === providedLockId;

return {
  json: {
    is_match: isMatch,
    already_released: false,
    provided_lock_id: providedLockId,
    stored_lock_id: parsedLock.lock_id,
    workflow_id: parsedLock.workflow_id,
    workflow_name: parsedLock.workflow_name,
    execution_id: parsedLock.execution_id || 'unknown',
    locked_at: parsedLock.locked_at
  }
};
